var expect = require('expect.js');
var AuthorizeItem = require('../../res/page/ruleadd/authorizeitem/authorizeitem');


describe('sqlscan-authorizeitem', function(){
  this.timeout(5000);
  before(function(){
    require('./mock-dev-env').mock();
  });
  after(function(){
    require('./mock-dev-env').unmock();
  });
  describe('#init authorizeitem()', function(){
    it('init authorizeitem', function(done){
      var authorizeitem = AuthorizeItem._create({
        events : {
          'aftercomplete' : function(){
            expect(authorizeitem).to.be.ok();
            var app = this.query('combobox[name=appId]');
            expect(app).to.be.ok();
            var owner = this.query('combobox[name=owner]');
            expect(owner).to.be.ok();
            done();
          },
          'afterloadmyownerappstore' : function(){
            var app = this.query('combobox[name=appId]');
            expect(app).to.be.ok();
            expect(app.records.length).to.be(2);
          }
        }
      });
    });
  });
  describe('#update authorizeitem()', function(){
    var mockData = {
      projectName : 'autotest',
      user: [{
        userName : 'chenxiang'
      },{
        userName : 'zhugong'
      }]
    };
    it('update authorizeitem', function(done){
      var authorizeitem = AuthorizeItem._create({
        value : JSON.stringify(mockData),
        events : {
          'aftercomplete' : function(){
            expect(authorizeitem).to.be.ok();
            var app = this.query('combobox[name=appId]');
            expect(app).to.be.ok();
            var owner = this.query('combobox[name=owner]');
            expect(owner).to.be.ok();
            done();
          },
          'afterloadmyownerappstore' : function(){
            var app = this.query('combobox[name=appId]');
            expect(app).to.be.ok();
            expect(app.records.length).to.be(2);
            expect(app.val()).to.be('autotest');
          },
          'afterloadappusersstore' : function(){
            var owner = this.query('combobox[name=owner]');
            expect(owner).to.be.ok();
            expect(owner.records.length).to.be(3);
            expect(owner.val()).to.eql(['chenxiang', 'zhugong']);
          }
        }
      });
    });
  });
  describe('#authorizeitem events', function(){
    it('authorizeitem events', function(done){
      var authorizeitem = AuthorizeItem._create({
        events : {
          'aftercomplete' : function(){
            var _self = this;
            expect(authorizeitem).to.be.ok();
            var btnRemove = this.query('button[name="btnRemove"]');
            expect(this.el).to.be.ok();
            btnRemove.emit('click');
            expect(this.el).not.to.be.ok();

            this.on('afterloadappusersstore', function(){
              var owner = _self.query('combobox[name=owner]');
              expect(owner.records.length).to.be(3);
            });
            var app = this.query('combobox[name=appId]');
            app.val('autotest');
            app.emit('change');
            done();
          }
        }
      });
    });
  });
});